mapper.select:
SELECT ( SELECT COUNT(*) FROM check_request cr INNER JOIN medical_technology mt ON mt.id = cr.medical_technology_id WHERE cr.check_state IN ('已完成', '已归档')
) AS "totalCompletedChecks", ( SELECT COUNT(*) FROM inspection_request ir INNER JOIN medical_technology mt ON mt.id = ir.medical_technology_id WHERE ir.inspection_state IN ('已完成', '已归档')
) AS "totalCompletedInspections", ( SELECT COUNT(*) FROM disposal_request dr INNER JOIN medical_technology mt ON mt.id = dr.medical_technology_id WHERE dr.disposal_state IN ('已完成', '已归档')
) AS "totalCompletedDisposals", ( SELECT COUNT(*) FROM check_request cr INNER JOIN medical_technology mt ON mt.id = cr.medical_technology_id WHERE cr.check_state IN ('已完成', '已归档') AND cr.check_time::date = CURRENT_DATE
) AS "todayCompletedChecks", ( SELECT COUNT(*) FROM inspection_request ir INNER JOIN medical_technology mt ON mt.id = ir.medical_technology_id WHERE ir.inspection_state IN ('已完成', '已归档') AND ir.inspection_time::date = CURRENT_DATE
) AS "todayCompletedInspections", ( SELECT COUNT(*) FROM disposal_request dr INNER JOIN medical_technology mt ON mt.id = dr.medical_technology_id WHERE dr.disposal_state IN ('已完成', '已归档') AND dr.disposal_time::date = CURRENT_DATE
) AS "todayCompletedDisposals"
